.search-dialog .search-nav .search-close-button:hover {
  color: #424153;
}
#search-mask {
  position: fixed;
  top: 0;
  right: 0;
  bottom: 0;
  left: 0;
  z-index: 1000;
  display: none;
  background: rgba(0,0,0,0.6);
}
#algolia-search .search-dialog .ais-SearchBox input {
